Javascript.validate:
            //Validation: Date cannot be in the past
            var checkDate = Services.getValue(PayableByDate.dataBinding); 
			var err = null;
			if( false == isFutureDate(checkDate))
			{ 	err = ErrorCode.getErrorCode("CaseMan_dateCannotBeInThePast_Msg");
			}		
			return err;

Javascript.transformToDisplay:
if (value != null)
{
	if (value.search(CaseManValidationHelper.YYYYMMDD_DATE_PATTERN) != -1)
	{
		return CaseManUtils.convertDateToDisplay(value);
	}
}
return value;
